#!/usr/bin/env node

import { spawn } from 'node:child_process';
import { performance } from 'node:perf_hooks';

type Format = 'gg' | 'json' | 'plain';

interface TimeoutTopology {
  command: string[];
  durationMs: number;
  startedAt: string;
  completedAt: string;
  elapsedUs: number;
  deadlineUnixUs: number;
  timedOut: boolean;
  exitCode: number | null;
  signal: NodeJS.Signals | null;
  stdoutBytes: number;
  stderrBytes: number;
}

function usage(): never {
  console.log(`timeout — sovereign deadline wrapper

Usage:
  timeout [--plain|--json|--gg] <duration> <command> [args...]

Durations: 500ms, 2s, 1m, 1h
`);
  process.exit(1);
}

function parseFormat(args: string[]): { format: Format; args: string[] } {
  let format: Format = 'gg';
  const filtered: string[] = [];
  for (const arg of args) {
    if (arg === '--plain') format = 'plain';
    else if (arg === '--json') format = 'json';
    else if (arg === '--gg') format = 'gg';
    else filtered.push(arg);
  }
  return { format, args: filtered };
}

function parseDuration(raw: string): number {
  const match = raw.match(/^(\d+)(ms|s|m|h)?$/);
  if (!match) throw new Error(`invalid duration: ${raw}`);
  const value = Number(match[1]);
  const unit = match[2] ?? 's';
  if (unit === 'ms') return value;
  if (unit === 's') return value * 1000;
  if (unit === 'm') return value * 60_000;
  return value * 3_600_000;
}

function esc(value: string): string {
  return value.replace(/\\/g, '\\\\').replace(/'/g, "\\'").replace(/\n/g, '\\n');
}

function renderGG(topology: TimeoutTopology): string {
  const command = topology.command.map(esc).join(' ');
  return [
    `(timeout: Timeout { duration_ms: ${topology.durationMs}, deadline_unix_us: ${topology.deadlineUnixUs}, elapsed_us: ${topology.elapsedUs}, timed_out: '${topology.timedOut}' })`,
    `(child: Process { command: '${command}', exit_code: '${topology.exitCode ?? ''}', signal: '${topology.signal ?? ''}', stdout_bytes: ${topology.stdoutBytes}, stderr_bytes: ${topology.stderrBytes} })`,
    `(timeout)-[:SPAWN]->(child)`,
    topology.timedOut ? `(timeout)-[:KILL { signal: 'SIGTERM' }]->(child)` : `(child)-[:FOLD]->(timeout)`,
  ].join('\n') + '\n';
}

function emit(topology: TimeoutTopology, format: Format) {
  if (format === 'json') console.log(JSON.stringify(topology, null, 2));
  else if (format === 'gg') process.stdout.write(renderGG(topology));
}

async function main() {
  const parsed = parseFormat(process.argv.slice(2));
  if (parsed.args.length < 2) usage();
  const durationMs = parseDuration(parsed.args[0]!);
  const command = parsed.args.slice(1);
  const started = performance.now();
  const startedAt = new Date();
  const deadlineUnixUs = (startedAt.getTime() + durationMs) * 1000;
  const child = spawn(command[0]!, command.slice(1), { stdio: ['inherit', 'pipe', 'pipe'] });
  let stdoutBytes = 0;
  let stderrBytes = 0;
  let timedOut = false;

  child.stdout.on('data', (chunk: Buffer) => {
    stdoutBytes += chunk.length;
    if (parsed.format === 'plain') process.stdout.write(chunk);
  });
  child.stderr.on('data', (chunk: Buffer) => {
    stderrBytes += chunk.length;
    if (parsed.format === 'plain') process.stderr.write(chunk);
  });

  const timer = setTimeout(() => {
    timedOut = true;
    child.kill('SIGTERM');
  }, durationMs);

  const result = await new Promise<{ code: number | null; signal: NodeJS.Signals | null }>((resolve) => {
    child.on('close', (code, signal) => resolve({ code, signal }));
  });
  clearTimeout(timer);

  const topology: TimeoutTopology = {
    command,
    durationMs,
    startedAt: startedAt.toISOString(),
    completedAt: new Date().toISOString(),
    elapsedUs: Math.round((performance.now() - started) * 1000),
    deadlineUnixUs,
    timedOut,
    exitCode: result.code,
    signal: result.signal,
    stdoutBytes,
    stderrBytes,
  };
  emit(topology, parsed.format);
  process.exit(timedOut ? 124 : result.code ?? 0);
}

main().catch((error: unknown) => {
  const message = error instanceof Error ? error.message : String(error);
  console.error(`timeout: ${message}`);
  process.exit(1);
});
